 			dL_dpixel[i] = dL_dpixels[i * H * W + pix_id];
-		dL_ddepth = dL_ddepths[pix_id];
+		dL_dpixel_depth = dL_dpixel_depths[pix_id];
 		dL_dalpha = dL_dalphas[pix_id];
 	}

